insert into public.knowledge_points (id,name,summary,core_fact,category,common_mistake,memory_tip,published,version) values
  ('civilization-river-civilizations','大河文明','早期文明多在大河流域发展，河流与文明对应是常见定位题。','古埃及依托尼罗河；古巴比伦位于两河流域；古印度关联印度河与恒河；古中国依托黄河、长江流域。','古代文明','把尼罗河、两河流域与相应文明混淆。','埃及尼罗，巴比两河，印度恒河，中国黄长。',true,1),
  ('civilization-hammurabi','汉谟拉比法典','古巴比伦王国的重要法典，反映古代两河流域文明的法律传统。','《汉谟拉比法典》是古巴比伦王国的法律文献。','古代文明','把法典归属错记为古埃及或古希腊。','汉谟拉比，对应古巴比伦。',true,1),
  ('civilization-homer','荷马史诗','古希腊文学的重要作品，包含《伊利亚特》和《奥德赛》。','《伊利亚特》《奥德赛》合称荷马史诗。','古典文化','把荷马史诗与古罗马史诗或中世纪作品混淆。','荷马两部：伊利亚特、奥德赛。',true,1),
  ('civilization-renaissance','文艺复兴','发端于意大利的思想文化运动，核心思潮是人文主义。','文艺复兴兴起于意大利，以人文主义为核心。','思想文化','把文艺复兴核心误写成神权至上或禁欲主义。','文艺复兴：意大利起，人文主义兴。',true,1),
  ('civilization-dante','但丁','欧洲从中世纪向近代过渡时期的重要诗人。','但丁的代表作是《神曲》。','思想文化','把《神曲》作者错记为莎士比亚或荷马。','但丁写《神曲》。',true,1),
  ('civilization-industrial-revolution','工业革命','机器生产和蒸汽动力的广泛应用推动社会生产方式深刻变化。','第一次工业革命首先在英国发生，瓦特改良蒸汽机是重要标志性技术。','近代变革','把蒸汽机的改良者、工业革命发端地混淆。','首工英，蒸汽看瓦特改良。',true,1),
  ('civilization-french-revolution','法国大革命','1789 年开始的法国资产阶级革命，推动近代民主思想传播。','1789 年巴黎人民攻占巴士底狱，法国大革命开始。','近代变革','把法国大革命开始与巴黎公社建立混为一谈。','法革一七八九，巴士底狱是开端。',true,1),
  ('civilization-paris-commune','巴黎公社','1871 年巴黎公社是无产阶级建立政权的伟大尝试。','巴黎公社建立于 1871 年。','近代变革','将巴黎公社时间错记为 1789 年法国大革命。','法革 1789，公社 1871。',true,1),
  ('civilization-communist-manifesto','共产党宣言','马克思、恩格斯共同起草的纲领性文献。','《共产党宣言》发表于 1848 年，作者是马克思和恩格斯。','思想文化','把作者、发表时间与《资本论》等著作混淆。','一八四八宣言出，马恩共同写。',true,1),
  ('civilization-ww1-paris','第一次世界大战与巴黎和会','第一次世界大战结束后，巴黎和会重塑战后国际秩序。','第一次世界大战于 1918 年结束；巴黎和会于 1919 年召开。','国际秩序','把巴黎和会误放在第二次世界大战之后。','一战十八止，巴黎和会十九开。',true,1),
  ('civilization-league-nations','国际联盟','第一次世界大战后建立的国际组织，是联合国的前身之一。','国际联盟在第一次世界大战后建立。','国际秩序','把国际联盟与联合国的成立背景、时间混淆。','一战后有国联，二战后有联合国。',true,1),
  ('civilization-ww2-un','第二次世界大战与联合国','反法西斯战争胜利后，联合国成立，国际合作进入新阶段。','第二次世界大战于 1945 年结束，联合国同年成立。','国际秩序','把联合国成立错放在第一次世界大战之后。','二战四五终，联合国四五生。',true,1)
