insert into public.questions (id,knowledge_id,level_id,question_type,stem,options,correct_answer,explanation,difficulty,published,version) values
  ('civilization-origin-01','civilization-river-civilizations','civilization-origin-1','single_choice','下列文明与其主要孕育河流对应正确的是？','{"questionId":"civilization-origin-01","knowledgeId":"civilization-river-civilizations","type":"single_choice","stem":"下列文明与其主要孕育河流对应正确的是？","options":[{"id":"A","text":"古埃及文明—尼罗河"},{"id":"B","text":"古巴比伦文明—恒河"},{"id":"C","text":"古印度文明—幼发拉底河"},{"id":"D","text":"古希腊文明—黄河"}]}'::jsonb,'"A"'::jsonb,'{"summary":"正确答案：古埃及文明—尼罗河","whyCorrect":"尼罗河孕育古埃及文明；古巴比伦在两河流域，古印度关联印度河与恒河。","whyUserAnswerWrong":"大河文明题先抓住河流这一定位信息。","commonMistake":"把两河流域、尼罗河和恒河对应关系记串。","memoryTip":"埃及尼罗，巴比两河，印度恒河，中国黄长。"}'::jsonb,2,true,1),
  ('civilization-origin-02','civilization-hammurabi','civilization-origin-1','single_choice','《汉谟拉比法典》属于哪一古代文明？','{"questionId":"civilization-origin-02","knowledgeId":"civilization-hammurabi","type":"single_choice","stem":"《汉谟拉比法典》属于哪一古代文明？","options":[{"id":"A","text":"古希腊文明"},{"id":"B","text":"古巴比伦文明"},{"id":"C","text":"古埃及文明"},{"id":"D","text":"古罗马文明"}]}'::jsonb,'"B"'::jsonb,'{"summary":"正确答案：古巴比伦文明","whyCorrect":"《汉谟拉比法典》是古巴比伦王国的重要法律文献。","whyUserAnswerWrong":"不要将两河流域文明成果错配给埃及、希腊或罗马。","commonMistake":"只记住法典名称，忽略其文明归属。","memoryTip":"汉谟拉比，对应古巴比伦。"}'::jsonb,2,true,1),
  ('civilization-origin-03','civilization-homer','civilization-origin-1','single_choice','下列作品中，属于荷马史诗的是？','{"questionId":"civilization-origin-03","knowledgeId":"civilization-homer","type":"single_choice","stem":"下列作品中，属于荷马史诗的是？","options":[{"id":"A","text":"《神曲》"},{"id":"B","text":"《奥德赛》"},{"id":"C","text":"《共产党宣言》"},{"id":"D","text":"《人间喜剧》"}]}'::jsonb,'"B"'::jsonb,'{"summary":"正确答案：《奥德赛》","whyCorrect":"《伊利亚特》和《奥德赛》合称荷马史诗。","whyUserAnswerWrong":"题目考查作品与作者、时代的基本对应。","commonMistake":"把《奥德赛》误认为近代文学作品。","memoryTip":"荷马两部：伊利亚特、奥德赛。"}'::jsonb,1,true,1),
  ('civilization-origin-04','civilization-renaissance','civilization-origin-1','single_choice','关于文艺复兴的表述，正确的是？','{"questionId":"civilization-origin-04","knowledgeId":"civilization-renaissance","type":"single_choice","stem":"关于文艺复兴的表述，正确的是？","options":[{"id":"A","text":"起源于法国，核心是神权至上"},{"id":"B","text":"起源于英国，核心是殖民扩张"},{"id":"C","text":"兴起于意大利，核心思潮是人文主义"},{"id":"D","text":"发生于古希腊时期，核心是城邦民主"}]}'::jsonb,'"C"'::jsonb,'{"summary":"正确答案：兴起于意大利，核心思潮是人文主义","whyCorrect":"文艺复兴发端于意大利，以人文主义为核心思潮。","whyUserAnswerWrong":"要分清古典文明、中世纪和近代思想运动的时间与地点。","commonMistake":"把文艺复兴与宗教改革、启蒙运动混淆。","memoryTip":"文艺复兴：意大利起，人文主义兴。"}'::jsonb,2,true,1),
  ('civilization-origin-05','civilization-dante','civilization-origin-1','single_choice','《神曲》的作者是？','{"questionId":"civilization-origin-05","knowledgeId":"civilization-dante","type":"single_choice","stem":"《神曲》的作者是？","options":[{"id":"A","text":"但丁"},{"id":"B","text":"荷马"},{"id":"C","text":"莎士比亚"},{"id":"D","text":"歌德"}]}'::jsonb,'"A"'::jsonb,'{"summary":"正确答案：但丁","whyCorrect":"《神曲》是但丁的代表作。","whyUserAnswerWrong":"文学常识题要同时记住作者、作品和所处时代。","commonMistake":"将《神曲》作者错记为莎士比亚。","memoryTip":"但丁写《神曲》。"}'::jsonb,1,true,1),
  ('civilization-modern-01','civilization-industrial-revolution','civilization-modern-1','single_choice','第一次工业革命首先发生在哪个国家？','{"questionId":"civilization-modern-01","knowledgeId":"civilization-industrial-revolution","type":"single_choice","stem":"第一次工业革命首先发生在哪个国家？","options":[{"id":"A","text":"法国"},{"id":"B","text":"英国"},{"id":"C","text":"美国"},{"id":"D","text":"德国"}]}'::jsonb,'"B"'::jsonb,'{"summary":"正确答案：英国","whyCorrect":"第一次工业革命首先在英国发生，蒸汽动力的应用推动机器生产发展。","whyUserAnswerWrong":"不要把后来的工业强国与第一次工业革命的发端地混淆。","commonMistake":"把第一次工业革命的起点错记为美国或德国。","memoryTip":"首工英，蒸汽看瓦特改良。"}'::jsonb,1,true,1),
  ('civilization-modern-02','civilization-industrial-revolution','civilization-modern-1','single_choice','下列人物与第一次工业革命的重要技术贡献对应正确的是？','{"questionId":"civilization-modern-02","knowledgeId":"civilization-industrial-revolution","type":"single_choice","stem":"下列人物与第一次工业革命的重要技术贡献对应正确的是？","options":[{"id":"A","text":"瓦特—改良蒸汽机"},{"id":"B","text":"爱迪生—发明蒸汽机"},{"id":"C","text":"牛顿—发明内燃机"},{"id":"D","text":"达尔文—发明火车"}]}'::jsonb,'"A"'::jsonb,'{"summary":"正确答案：瓦特—改良蒸汽机","whyCorrect":"瓦特改良蒸汽机是第一次工业革命的标志性技术之一。","whyUserAnswerWrong":"注意“改良蒸汽机”而非笼统记为“发明蒸汽机”。","commonMistake":"将蒸汽机、内燃机和电力技术混为同一时期。","memoryTip":"蒸汽看瓦特改良。"}'::jsonb,2,true,1),
  ('civilization-modern-03','civilization-french-revolution','civilization-modern-1','single_choice','法国大革命开始的标志性事件是？','{"questionId":"civilization-modern-03","knowledgeId":"civilization-french-revolution","type":"single_choice","stem":"法国大革命开始的标志性事件是？","options":[{"id":"A","text":"巴黎公社成立"},{"id":"B","text":"攻占巴士底狱"},{"id":"C","text":"发表《共产党宣言》"},{"id":"D","text":"召开巴黎和会"}]}'::jsonb,'"B"'::jsonb,'{"summary":"正确答案：攻占巴士底狱","whyCorrect":"1789 年巴黎人民攻占巴士底狱，法国大革命开始。","whyUserAnswerWrong":"巴黎公社是 1871 年事件，与法国大革命的开端相隔数十年。","commonMistake":"将 1789 年和 1871 年的巴黎事件混淆。","memoryTip":"法革一七八九，巴士底狱是开端。"}'::jsonb,2,true,1),
  ('civilization-modern-04','civilization-paris-commune','civilization-modern-1','single_choice','巴黎公社建立于哪一年？','{"questionId":"civilization-modern-04","knowledgeId":"civilization-paris-commune","type":"single_choice","stem":"巴黎公社建立于哪一年？","options":[{"id":"A","text":"1789 年"},{"id":"B","text":"1848 年"},{"id":"C","text":"1871 年"},{"id":"D","text":"1917 年"}]}'::jsonb,'"C"'::jsonb,'{"summary":"正确答案：1871 年","whyCorrect":"巴黎公社建立于 1871 年。","whyUserAnswerWrong":"1789 年是法国大革命开始，1848 年是《共产党宣言》发表。","commonMistake":"将巴黎公社与法国大革命混为同一事件。","memoryTip":"法革 1789，公社 1871。"}'::jsonb,2,true,1),
  ('civilization-modern-05','civilization-communist-manifesto','civilization-modern-1','single_choice','《共产党宣言》的共同作者是？','{"questionId":"civilization-modern-05","knowledgeId":"civilization-communist-manifesto","type":"single_choice","stem":"《共产党宣言》的共同作者是？","options":[{"id":"A","text":"马克思和恩格斯"},{"id":"B","text":"马克思和列宁"},{"id":"C","text":"恩格斯和卢梭"},{"id":"D","text":"列宁和斯大林"}]}'::jsonb,'"A"'::jsonb,'{"summary":"正确答案：马克思和恩格斯","whyCorrect":"《共产党宣言》由马克思、恩格斯共同起草，发表于 1848 年。","whyUserAnswerWrong":"马克思主义经典著作要注意作者组合和发表时间。","commonMistake":"将马克思、恩格斯与后来的革命家混淆。","memoryTip":"一八四八宣言出，马恩共同写。"}'::jsonb,2,true,1),
  ('civilization-modern-06','civilization-ww1-paris','civilization-modern-1','single_choice','下列关于第一次世界大战与巴黎和会的时间顺序，正确的是？','{"questionId":"civilization-modern-06","knowledgeId":"civilization-ww1-paris","type":"single_choice","stem":"下列关于第一次世界大战与巴黎和会的时间顺序，正确的是？","options":[{"id":"A","text":"巴黎和会召开后，第一次世界大战结束"},{"id":"B","text":"第一次世界大战结束后，巴黎和会召开"},{"id":"C","text":"巴黎和会与第一次世界大战同时开始"},{"id":"D","text":"巴黎和会在第二次世界大战后召开"}]}'::jsonb,'"B"'::jsonb,'{"summary":"正确答案：第一次世界大战结束后，巴黎和会召开","whyCorrect":"第一次世界大战于 1918 年结束，巴黎和会于 1919 年召开。","whyUserAnswerWrong":"先记一战结束，再记战后秩序安排。","commonMistake":"误将巴黎和会放在二战之后。","memoryTip":"一战十八止，巴黎和会十九开。"}'::jsonb,2,true,1),
  ('civilization-modern-07','civilization-league-nations','civilization-modern-1','single_choice','国际联盟建立的历史背景是？','{"questionId":"civilization-modern-07","knowledgeId":"civilization-league-nations","type":"single_choice","stem":"国际联盟建立的历史背景是？","options":[{"id":"A","text":"第一次世界大战后"},{"id":"B","text":"法国大革命后"},{"id":"C","text":"第二次世界大战后"},{"id":"D","text":"工业革命前"}]}'::jsonb,'"A"'::jsonb,'{"summary":"正确答案：第一次世界大战后","whyCorrect":"国际联盟是在第一次世界大战后建立的国际组织。","whyUserAnswerWrong":"第二次世界大战后成立的是联合国。","commonMistake":"将国联与联合国的时代背景颠倒。","memoryTip":"一战后有国联，二战后有联合国。"}'::jsonb,1,true,1),
  ('civilization-modern-08','civilization-ww2-un','civilization-modern-1','single_choice','联合国成立于哪一年？','{"questionId":"civilization-modern-08","knowledgeId":"civilization-ww2-un","type":"single_choice","stem":"联合国成立于哪一年？","options":[{"id":"A","text":"1919 年"},{"id":"B","text":"1939 年"},{"id":"C","text":"1945 年"},{"id":"D","text":"1949 年"}]}'::jsonb,'"C"'::jsonb,'{"summary":"正确答案：1945 年","whyCorrect":"第二次世界大战于 1945 年结束，联合国同年成立。","whyUserAnswerWrong":"1919 年与战后国际联盟相关，1949 年与新中国成立相关。","commonMistake":"把国联与联合国成立年份混淆。","memoryTip":"二战四五终，联合国四五生。"}'::jsonb,1,true,1),
  ('civilization-modern-09','civilization-french-revolution','civilization-modern-1','single_choice','法国大革命开始于哪一年？','{"questionId":"civilization-modern-09","knowledgeId":"civilization-french-revolution","type":"single_choice","stem":"法国大革命开始于哪一年？","options":[{"id":"A","text":"1640 年"},{"id":"B","text":"1776 年"},{"id":"C","text":"1848 年"},{"id":"D","text":"1789 年"}]}'::jsonb,'"D"'::jsonb,'{"summary":"正确答案：1789 年","whyCorrect":"1789 年巴黎人民攻占巴士底狱，法国大革命开始。","whyUserAnswerWrong":"1640 年常与英国资产阶级革命相关，1848 年常与《共产党宣言》相关。","commonMistake":"只记住事件名称而错过关键年份。","memoryTip":"法革一七八九，巴士底狱是开端。"}'::jsonb,2,true,1),
  ('civilization-modern-10','civilization-communist-manifesto','civilization-modern-1','single_choice','《共产党宣言》发表于哪一年？','{"questionId":"civilization-modern-10","knowledgeId":"civilization-communist-manifesto","type":"single_choice","stem":"《共产党宣言》发表于哪一年？","options":[{"id":"A","text":"1789 年"},{"id":"B","text":"1871 年"},{"id":"C","text":"1917 年"},{"id":"D","text":"1848 年"}]}'::jsonb,'"D"'::jsonb,'{"summary":"正确答案：1848 年","whyCorrect":"《共产党宣言》发表于 1848 年，由马克思、恩格斯共同起草。","whyUserAnswerWrong":"1789 年是法国大革命开始，1871 年是巴黎公社建立。","commonMistake":"把近代革命时间节点混成一条线。","memoryTip":"一八四八宣言出，马恩共同写。"}'::jsonb,2,true,1),
  ('civilization-modern-11','civilization-ww1-paris','civilization-modern-1','single_choice','巴黎和会召开于哪一年？','{"questionId":"civilization-modern-11","knowledgeId":"civilization-ww1-paris","type":"single_choice","stem":"巴黎和会召开于哪一年？","options":[{"id":"A","text":"1914 年"},{"id":"B","text":"1918 年"},{"id":"C","text":"1945 年"},{"id":"D","text":"1919 年"}]}'::jsonb,'"D"'::jsonb,'{"summary":"正确答案：1919 年","whyCorrect":"第一次世界大战结束后，巴黎和会于 1919 年召开。","whyUserAnswerWrong":"1914 年是一战爆发，1918 年是一战结束。","commonMistake":"把战争爆发、结束与战后会议的年份混淆。","memoryTip":"一战十八止，巴黎和会十九开。"}'::jsonb,2,true,1),
  ('civilization-boss-01','civilization-renaissance','civilization-boss','single_choice','下列“人物—作品—时代”对应正确的是？','{"questionId":"civilization-boss-01","knowledgeId":"civilization-renaissance","type":"single_choice","stem":"下列“人物—作品—时代”对应正确的是？","options":[{"id":"A","text":"但丁—《神曲》—文艺复兴前后的人文主义先驱"},{"id":"B","text":"荷马—《共产党宣言》—工业革命"},{"id":"C","text":"马克思—《奥德赛》—古希腊"},{"id":"D","text":"瓦特—《伊利亚特》—古罗马"}]}'::jsonb,'"A"'::jsonb,'{"summary":"正确答案：但丁—《神曲》—文艺复兴前后的人文主义先驱","whyCorrect":"但丁是欧洲由中世纪向近代过渡时期的重要诗人，《神曲》是其代表作。","whyUserAnswerWrong":"综合题要同时核对人物、作品与时代三个维度。","commonMistake":"把古希腊史诗、近代政治文献与作者错配。","memoryTip":"但丁写《神曲》，文艺复兴前奏。"}'::jsonb,3,true,1),
  ('civilization-boss-02','civilization-ww2-un','civilization-boss','single_choice','下列国际组织与其成立背景的对应，正确的是？','{"questionId":"civilization-boss-02","knowledgeId":"civilization-ww2-un","type":"single_choice","stem":"下列国际组织与其成立背景的对应，正确的是？","options":[{"id":"A","text":"国际联盟—第二次世界大战后"},{"id":"B","text":"联合国—第二次世界大战后"},{"id":"C","text":"联合国—第一次世界大战后"},{"id":"D","text":"国际联盟—工业革命后"}]}'::jsonb,'"B"'::jsonb,'{"summary":"正确答案：联合国—第二次世界大战后","whyCorrect":"国际联盟在一战后建立，联合国在二战后成立。","whyUserAnswerWrong":"要把“战后国际秩序”对应到具体战争。","commonMistake":"把国联和联合国的建立背景颠倒。","memoryTip":"一战后国联，二战后联合国。"}'::jsonb,2,true,1),
  ('civilization-boss-03','civilization-industrial-revolution','civilization-boss','single_choice','按时间先后排列，下列事件正确的是？','{"questionId":"civilization-boss-03","knowledgeId":"civilization-industrial-revolution","type":"single_choice","stem":"按时间先后排列，下列事件正确的是？","options":[{"id":"A","text":"巴黎公社—法国大革命—联合国成立"},{"id":"B","text":"联合国成立—工业革命—法国大革命"},{"id":"C","text":"法国大革命—工业革命—巴黎公社"},{"id":"D","text":"工业革命—法国大革命—巴黎公社"}]}'::jsonb,'"D"'::jsonb,'{"summary":"正确答案：工业革命—法国大革命—巴黎公社","whyCorrect":"第一次工业革命始于 18 世纪 60 年代，法国大革命开始于 1789 年，巴黎公社建立于 1871 年。","whyUserAnswerWrong":"先写出关键年份或世纪，再比较顺序。","commonMistake":"将工业革命与法国大革命的先后颠倒。","memoryTip":"六十年代工业起，八九法国大革命，七一巴黎公社。"}'::jsonb,4,true,1),
  ('civilization-boss-04','civilization-river-civilizations','civilization-boss','single_choice','下列关于世界文明演进的表述，正确的是？','{"questionId":"civilization-boss-04","knowledgeId":"civilization-river-civilizations","type":"single_choice","stem":"下列关于世界文明演进的表述，正确的是？","options":[{"id":"A","text":"《汉谟拉比法典》产生于古希腊城邦"},{"id":"B","text":"荷马史诗属于近代工业文学"},{"id":"C","text":"文艺复兴兴起于意大利并倡导人文主义"},{"id":"D","text":"国际联盟成立于第二次世界大战后"}]}'::jsonb,'"C"'::jsonb,'{"summary":"正确答案：文艺复兴兴起于意大利并倡导人文主义","whyCorrect":"该表述准确概括了文艺复兴的地点与核心思潮。","whyUserAnswerWrong":"其他选项分别混淆了文明归属、作品时代和国际组织背景。","commonMistake":"把古典文化、近代思想和国际秩序混在同一时代。","memoryTip":"按文明—思想—变革—战后秩序建立长线。"}'::jsonb,3,true,1)
